SELECT ?country ?countryLabel (MAX(?numMembers) AS ?maxMembers) WHERE {
  wd:Q142 wdt:P463 ?country.
  ?country wdt:P36 ?parliament.
  ?parliament wdt:P1159 ?chamber.
  ?chamber wdt:P2046 ?numMembers.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
} GROUP BY ?country ?countryLabel

SELECT ?country ?countryLabel ?numMembers WHERE {
  wd:Q142 wdt:P463 ?country.
  ?country rdfs:label ?countryLabel.
  FILTER (LANGMATCHES(LANG(?countryLabel), "en"))
  { ?country wdt:P1551 ?chamber; wdt:P2046 ?numMembers }
  UNION
  { ?country wdt:P122 ?chamber; wdt:P2046 ?numMembers }
}

SELECT DISTINCT ?country ?countryLabel ?numMembers WHERE {
  ?country wdt:P463 wd:Q142.
  ?country rdfs:label ?countryLabel.
  FILTER (LANG(?countryLabel) = 'en')

  UNION

  {
    # Case 1: Unicameral legislatures
    ?country wdt:P1551 ?legislature.
    ?legislature wdt:P2046 ?numMembers.
  }
  UNION
  {
    # Case 2: Bicameral legislatures (lower house)
    ?country wdt:P1551 ?legislature.
    ?legislature wdt:P1159 ?chamber.
    ?chamber wdt:P553 wd:Q2535417.  # Lower house
    ?chamber wdt:P2046 ?numMembers.
  }
}

